var e=[{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`끄아아아악!`,JPN:`クアアアアッ！`,ENG:`Aaaagh!`,TWN:`啊啊啊啊！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`초, 총이 통하질 않아!`,JPN:`じゅ、銃が通じない！`,ENG:`Th-the guns aren't working against it!`,TWN:`子，子彈打不透！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`보통 놈이 아니야! 다들 도망쳐!`,JPN:`ただモンじゃねえ！　みんな逃げろ！`,ENG:`That's no ordinary C.O.! RUN!`,TWN:`看來不是普通的傢伙！大家快逃！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_ALL_DAGGER_STING_SMALL_03`},{id:`L9_1`,type:`dialog`,speaker:`PMC_NPC_COMPLETE_B`,text:{KOREA:`여긴 틀렸어! 어서 피하자!`,JPN:`ここはダメだ！　早く逃げよう！`,ENG:`We gotta go, NOW!`,TWN:`這裡失守了！快躲起來！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`네? 하지만 다른 분들은 어떻게 해요? 도와 드려야죠!`,JPN:`え？　でも他の方はどうするんですか？　手伝ってあげないと！`,ENG:`Huh? But what about the others? We have to help them!`,TWN:`什麼？那其他人怎麼辦？必須幫幫他們！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`PMC_NPC_COMPLETE_A`,text:{KOREA:`돕긴 뭘 도와? 헛소리 하지 말고 뛰어!`,JPN:`何を手伝うんだよ！　いいから走れ！`,ENG:`Help yourself! Cut the nonsense and run!`,TWN:`幫什麼幫？說什麼傻話，快跑！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PMC_NPC_COMPLETE_A`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`앗, 잠깐만요! 손 잡아끌지 마시고요!`,JPN:`あっ、ちょっと！　手を引っ張らないで！`,ENG:`Oh, wait! Let go of my hand!`,TWN:`喂，先等一下！不要拉著我跑啦！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`PMC_NPC_COMPLETE_A`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L15_1`,type:`dialog`,speaker:`PMC_NPC_COMPLETE_B`,text:{KOREA:`커헉……!`,JPN:`かはっ……！`,ENG:`Kuh...!`,TWN:`唔……！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`아저씨!!`,JPN:`おじさん！！`,ENG:`Mister!!`,TWN:`大叔！！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`도망쳐. 가. 안 되겠어.`,JPN:`ニゲロ。イケ。ダメダ。`,ENG:`You. Cannot. Run away.`,TWN:`快逃，走，糟糕。`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`죽어.`,JPN:`シネ。`,ENG:`Die.`,TWN:`死掉。`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`PMC_NPC_COMPLETE_A`,text:{KOREA:`저 개자식…!`,JPN:`あのクソ野郎が……！`,ENG:`You bastard...!`,TWN:`該死的傢伙…！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PMC_NPC_COMPLETE_A`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PMC_NPC_COMPLETE_A`,text:{KOREA:`학생, 따라와! 여기 있다간 우리 모두 다 죽어!`,JPN:`ついて来い！　ここにいたらみんな死ぬぞ！`,ENG:`Kid, follow me! We're all toast if we stay here any longer!`,TWN:`小丫頭，你跟我來！繼續待在這裡我們都會死的！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PMC_NPC_COMPLETE_A`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`아, 알겠어요!`,JPN:`わ、わかりました！`,ENG:`O-okay!`,TWN:`喔喔，好！`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`잔챙이들. 싫다. 너희들. 이. 잡. 아.`,JPN:`雑魚。イヤ。オ前ラ。ガ。捕マエ。ロ。`,ENG:`Little ones. Hate. You. Get. Them.`,TWN:`小嘍囉，討厭，你們，抓住。`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`죽여라.`,JPN:`殺セ。`,ENG:`Kill them.`,TWN:`殺死他們。`},stage:{bg:`DOCK_DAY`,bgm:`BATTLE_BOSS_EPIC_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};